# Building MCP Clients

An MCP client connects a host application (like a chatbot or IDE) to one or more MCP servers. The client handles protocol communication: initialization, capability negotiation, tool discovery, tool execution, resource reading, and prompt retrieval.

## Python Client

```python
import asyncio
from mcp import ClientSession, StdioServerParameters
from mcp.client.stdio import stdio_client

async def main():
    # Define the server to connect to
    server_params = StdioServerParameters(
        command="python",
        args=["path/to/server.py"],
        env=None
    )

    # Connect via stdio transport
    async with stdio_client(server_params) as (read, write):
        async with ClientSession(read, write) as session:
            # Initialize the connection
            await session.initialize()

            # Discover available tools
            tools = await session.list_tools()
            print(f"Available tools: {[t.name for t in tools.tools]}")

            # Call a tool
            result = await session.call_tool(
                "get_weather",
                arguments={"city": "San Francisco"}
            )
            print(result.content[0].text)

            # List resources
            resources = await session.list_resources()

            # Read a resource
            content = await session.read_resource("schema://database")

            # List prompts
            prompts = await session.list_prompts()

            # Get a prompt
            prompt = await session.get_prompt(
                "code_review",
                arguments={"code": "def hello(): pass"}
            )

asyncio.run(main())
```

## TypeScript Client

```typescript
import { Client } from "@modelcontextprotocol/sdk/client/index.js";
import { StdioClientTransport } from "@modelcontextprotocol/sdk/client/stdio.js";

const transport = new StdioClientTransport({
  command: "python",
  args: ["path/to/server.py"]
});

const client = new Client(
  { name: "my-client", version: "1.0.0" },
  { capabilities: {} }
);

await client.connect(transport);

// Discover tools
const tools = await client.listTools();
console.log(tools.tools.map(t => t.name));

// Call a tool
const result = await client.callTool({
  name: "get_weather",
  arguments: { city: "San Francisco" }
});

// Read a resource
const resource = await client.readResource({
  uri: "schema://database"
});

// Get a prompt
const prompt = await client.getPrompt({
  name: "code_review",
  arguments: { code: "def hello(): pass" }
});
```

## Remote Server Connection (Streamable HTTP)

```python
from mcp.client.streamable_http import streamablehttp_client

async with streamablehttp_client("https://mcp.example.com/mcp") as (read, write, session_id):
    async with ClientSession(read, write) as session:
        await session.initialize()
        tools = await session.list_tools()
```

```typescript
import { StreamableHTTPClientTransport } from "@modelcontextprotocol/sdk/client/streamableHttp.js";

const transport = new StreamableHTTPClientTransport(
  new URL("https://mcp.example.com/mcp")
);
await client.connect(transport);
```

## LLM Integration Pattern

The standard pattern for integrating MCP tools with an LLM:

```python
import anthropic

# 1. Discover tools from all MCP servers
all_tools = []
for session in mcp_sessions:
    response = await session.list_tools()
    for tool in response.tools:
        all_tools.append({
            "name": tool.name,
            "description": tool.description,
            "input_schema": tool.inputSchema
        })

# 2. Send to LLM with tools
client = anthropic.Anthropic()
response = client.messages.create(
    model="claude-sonnet-4-6",
    max_tokens=1024,
    messages=messages,
    tools=all_tools
)

# 3. Handle tool calls
for block in response.content:
    if block.type == "tool_use":
        # Route to the right MCP session
        session = find_session_for_tool(block.name)
        result = await session.call_tool(block.name, block.input)
        # Feed result back to LLM
        messages.append({"role": "assistant", "content": response.content})
        messages.append({
            "role": "user",
            "content": [{"type": "tool_result", "tool_use_id": block.id, "content": result.content[0].text}]
        })
```

## Managing Multiple Servers

A host typically connects to multiple MCP servers simultaneously:

```python
servers = [
    StdioServerParameters(command="python", args=["filesystem_server.py"]),
    StdioServerParameters(command="python", args=["database_server.py"]),
    StdioServerParameters(command="node", args=["github_server.js"]),
]

sessions = []
for server in servers:
    transport = await stdio_client(server)
    session = ClientSession(*transport)
    await session.initialize()
    sessions.append(session)

# Aggregate tools from all servers
all_tools = []
for session in sessions:
    tools = await session.list_tools()
    all_tools.extend(tools.tools)
```

## Handling Notifications

```python
# React to tool list changes
async def on_tools_changed():
    tools = await session.list_tools()
    update_available_tools(tools)

session.on_notification("notifications/tools/list_changed", on_tools_changed)
```

## Environment Variables

| Variable | Purpose |
|----------|----------|
| `MCP_SERVER_URL` | URL for remote Streamable HTTP servers |
| `MCP_AUTH_TOKEN` | Bearer token for authenticated servers |
| `ANTHROPIC_API_KEY` | API key for LLM integration with Claude |
